[CmdletBinding()]
param([Parameter(Mandatory)][string]$ProjectRoot,[Parameter(Mandatory)][string]$Path)
$ErrorActionPreference='Stop';$project=(Resolve-Path $ProjectRoot).Path;$d=Get-Content -Raw $Path|ConvertFrom-Json;$errors=[Collections.Generic.List[string]]::new();$assignmentPath=Join-Path $project ('.studio/runtime/assignments/'+$d.role+'.json');if(-not(Test-Path $assignmentPath)){$errors.Add('DELTA_ASSIGNMENT_MISSING')}else{$a=Get-Content -Raw $assignmentPath|ConvertFrom-Json;foreach($required in @('schemaVersion','role','status','taskIds','criteriaCompleted','criteriaBlocked','filesChanged','ruleIdsApplied','approvedExceptions','dependenciesAdded','dependenciesRemoved','commands','runtimeEvidence','knownGaps','handoff','generatedAt')){if($null -eq $d.$required){$errors.Add('DELTA_FIELD_MISSING:'+ $required)}};foreach($id in @($d.criteriaCompleted)){if($id -notin @($a.criteriaIds)){$errors.Add('DELTA_UNOWNED_CRITERION')}};foreach($file in @($d.filesChanged)){if(@($a.allowedPaths|Where-Object{$file -like ($_ -replace '/','\' -replace '\*\*','*')}).Count -eq 0){$errors.Add('DELTA_UNOWNED_FILE')}}};foreach($command in @($d.commands)){if($command.result -eq 'passed' -and [string]::IsNullOrWhiteSpace($command.evidence)){$errors.Add('DELTA_COMMAND_WITHOUT_EVIDENCE')}};foreach($evidence in @($d.runtimeEvidence)){if([string]$evidence -match '(?i)source review|static inspection'){$errors.Add('DELTA_INFERRED_RUNTIME_EVIDENCE')}};if($d.status -in @('blocked','failed') -and @($d.knownGaps).Count -eq 0 -and @($d.criteriaBlocked).Count -eq 0){$errors.Add('DELTA_BLOCKED_WITHOUT_REASON')};if($errors.Count){throw ($errors -join ';')};[pscustomobject]@{valid=$true;role=$d.role}
